 */
function resolveLogDir(): string {
  const projectPath = LOG_PATHS.project;
  if (existsSync(projectPath)) {
    return projectPath;
  }

  const userPath = LOG_PATHS.user.replace("~", homedir());
  if (existsSync(userPath)) {
    return userPath;
  }

  return projectPath;
}

