              "\u23F3     exec (2/3)...\n",
              "\u2713     exec (2/3) (20s)\n",
              "\u23F3     qa (3/3)...\n",
              "\u2713     qa (3/3) (5s)\n",
            ],
          }),
        );

        await client.callTool(
          { name: "sequant_run", arguments: { issues: [421] } },
          { _meta: { progressToken: "tok-phases" } },
        );

