        expect(result.isError).toBeFalsy();
        expect(progressEvents).toHaveLength(0);
      });

      it("should handle partial/malformed phase output", async () => {
        const progressEvents: unknown[] = [];
        client.setNotificationHandler(
          { method: "notifications/progress" },
          (params: unknown) => {
            progressEvents.push(params);
          },
        );

        mockedSpawn.mockImplementation(() =>
          createMockProcessWithPhaseOutput({
            exitCode: 0,
            stdoutChunks: [
              "\u23F3 spec\n", // missing (N/M)
              "random noise\n",
              "\u23F3     exec (2/3)...\n", // valid
            ],
          }),
        );

        const result = await client.callTool(
          { name: "sequant_run", arguments: { issues: [421] } },
          { _meta: { progressToken: "tok-malformed" } },
        );

        await new Promise((r) => setTimeout(r, 50));

        expect(result.isError).toBeFalsy();
        // Only the valid line should trigger a notification
        expect(progressEvents).toHaveLength(1);
      });

      it("should handle concurrent runs with separate progress tracking", async () => {
        const events1: Array<{ progressToken: string | number }> = [];
        const events2: Array<{ progressToken: string | number }> = [];

        client.setNotificationHandler(
          { method: "notifications/progress" },
          (params: { progressToken: string | number }) => {
            if (params.progressToken === "tok-run1") events1.push(params);
            if (params.progressToken === "tok-run2") events2.push(params);
          },
        );

        mockedSpawn.mockImplementation(() =>
          createMockProcessWithPhaseOutput({
            exitCode: 0,
            stdoutChunks: ["\u23F3     spec (1/3)...\n"],
          }),
        );

        // Fire both runs concurrently
        const [result1, result2] = await Promise.all([
          client.callTool(
            { name: "sequant_run", arguments: { issues: [100] } },
            { _meta: { progressToken: "tok-run1" } },
          ),
          client.callTool(
            { name: "sequant_run", arguments: { issues: [200] } },
            { _meta: { progressToken: "tok-run2" } },
          ),
        ]);

        await new Promise((r) => setTimeout(r, 50));

        expect(result1.isError).toBeFalsy();
        expect(result2.isError).toBeFalsy();
        // Each run should have its own token
        expect(events1.length).toBeGreaterThanOrEqual(1);
        expect(events2.length).toBeGreaterThanOrEqual(1);
        expect(events1[0].progressToken).toBe("tok-run1");
        expect(events2[0].progressToken).toBe("tok-run2");
      });
    });
  },
);

